=== SHELL SCRIPT: scripts/e2e-test.sh ===
#!/bin/bash
set -euo pipefail
echo "[E2E] Starting end-to-end test suite..."
echo "[E2E] Starting dev server..."
bun run dev &
DEV_PID=$!
sleep 5
echo "[E2E] Dev server PID: $DEV_PID"
echo "[E2E] Running integration tests..."
bun run vitest run __tests__/e2e-integration.test.ts --reporter=verbose 2>&1 | tee e2e-results.log
EXIT_CODE=${PIPESTATUS[0]}
echo "[E2E] Stopping dev server..."
kill $DEV_PID 2>/dev/null || true
echo "[E2E] Exit code: $EXIT_CODE"
exit $EXIT_CODE

Implement browser-side audio capture per spec §10.1.

FILE: public/audio-processor.js (MUST be vanilla JavaScript, not TypeScript — AudioWorklet runs in a separate thread/context that cannot import TS modules)
FILE: lib/audio/capture.ts (main thread wrapper)

=== AudioWorklet Processor (public/audio-processor.js) ===

The processor captures mic audio at the browser native sample rate (typically 48000Hz or 44100Hz) as Float32, then downsamples to 16kHz and converts to Int16 (little-endian) for the Gemini Live API.

class AudioCaptureProcessor extends AudioWorkletProcessor {
  constructor() {
    super();
    this.buffer = [];
  }

  process(inputs) {
    const input = inputs[0]?.[0]; // mono channel
    if (!input) return true;

    // Accumulate samples
    this.buffer.push(...input);

    // Process in chunks when we have enough
    const CHUNK_SIZE = 4800; // 100ms at 48kHz
    while (this.buffer.length >= CHUNK_SIZE) {
      const chunk = this.buffer.splice(0, CHUNK_SIZE);
      const downsampled = this.downsample(chunk, sampleRate, 16000);
      const int16 = this.float32ToInt16(downsampled);
      this.port.postMessage(int16.buffer, [int16.buffer]);
    }
    return true;
  }

  downsample(samples, fromRate, toRate) {
    // For 48kHz → 16kHz: every 3rd sample (simple decimation)
    // For 44100Hz → 16kHz: linear interpolation
    const ratio = fromRate / toRate;
    const outputLength = Math.floor(samples.length / ratio);
    const output = new Float32Array(outputLength);
    for (let i = 0; i < outputLength; i++) {
      const srcIndex = i * ratio;
      const srcFloor = Math.floor(srcIndex);
      const srcCeil = Math.min(srcFloor + 1, samples.length - 1);
      const frac = srcIndex - srcFloor;
      output[i] = samples[srcFloor] * (1 - frac) + samples[srcCeil] * frac;
    }
    return output;
  }

  float32ToInt16(float32Array) {
    const int16 = new Int16Array(float32Array.length);
    for (let i = 0; i < float32Array.length; i++) {
      const s = Math.max(-1, Math.min(1, float32Array[i]));
      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return int16;
  }
}
registerProcessor("audio-capture-processor", AudioCaptureProcessor);

=== Main Thread Wrapper (lib/audio/capture.ts) ===

export class AudioCapture {
  private audioContext: AudioContext | null = null;
  private workletNode: AudioWorkletNode | null = null;
  private stream: MediaStream | null = null;
  public onChunk: ((data: ArrayBuffer) => void) | null = null;

  async start() {
    this.audioContext = new AudioContext();
    await this.audioContext.audioWorklet.addModule("/audio-processor.js");
    this.stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = this.audioContext.createMediaStreamSource(this.stream);
    this.workletNode = new AudioWorkletNode(this.audioContext, "audio-capture-processor");
    this.workletNode.port.onmessage = (event) => {
      if (this.onChunk) this.onChunk(event.data);
    };
    source.connect(this.workletNode);
    // Do NOT connect workletNode to destination (we dont want to hear ourselves)
  }

  stop() {
    this.stream?.getTracks().forEach(t => t.stop());
    this.workletNode?.disconnect();
    this.audioContext?.close();
    this.audioContext = null;
  }
}

=== Tab Visibility Handler (spec §10.2) ===
document.addEventListener("visibilitychange", () => {
  if (document.visibilityState === "visible" && audioContext) {
    audioContext.resume();
  }
});

IMPORTANT NOTES:
- The processor file MUST be in public/ and served as a static JS file
- AudioWorklet does NOT support import statements in the processor file
- The browser native rate varies: 48000Hz (most systems), 44100Hz (some Macs), others possible
- sampleRate is available as a global in the AudioWorklet processor context
- MIME type for Gemini: audio/pcm;rate=16000
- Chunks should be ~100ms for smooth streaming (1600 Int16 samples per chunk at 16kHz)

